#include<bits/stdc++.h>
using namespace std;
long long exgcd(long long a,long long b,long long &x,long long &y)
{
    if(b==0)
    {
        x=1;
        y=0;
        return a;
    }
    long long g=exgcd(b,a%b,x,y);
    long long tx=x;
    x=y;
    y=tx-(a/b)*y;
    return g;
}
int main()
{
    long long x,y,m,n,l;
    scanf("%lld%lld%lld%lld%lld",&x,&y,&m,&n,&l);
    long long a=n-m,b=l,c=x-y,X,Y;
    if(a<0)
    {
        a=-a;
        c=-c;
    }
    long long g=exgcd(a,b,X,Y);
    if(c%g!=0)
    {
        printf("Impossible");
        return 0;
    }
    a/=g;
    b/=g;
    c/=g;
    X*=c;
    X=(X%b+b)%b;
    printf("%lld",X);
    return 0;
}
